const response = $input.all()[0].json;
const intake = $('Transform to API Format').all()[0].json.intake;

return {
  json: {
    status: 'success',
    message: `Report generated for ${response.summary?.client || intake.client_name || 'client'}`,
    execution_id: response.execution_id,
    client: response.summary?.client || intake.client_name,
    contact_email: intake.contact_email || '',
    total_price: response.summary?.total_price,
    total_hours: response.summary?.total_hours,
    audit_score: response.summary?.audit_score,
    artifacts: response.artifacts,
    html_url: response.artifacts?.html,
    pdf_url: response.artifacts?.pdf,
    json_url: response.artifacts?.json
  }
};

const response = $input.all()[0].json;
const intake = $('Transform to API Format').all()[0].json.intake;

return {
  json: {
    status: 'error',
    message: response.error || 'Report generation failed',
    client: intake.client_name || 'Unknown',
    contact_email: intake.contact_email || '',
    execution_id: response.execution_id || null,
    details: response
  }
};

const formData = $input.all()[0].json.body || $input.all()[0].json;
const required = ['client_name', 'q01_workflow_name', 'q02_trigger_event', 'q03_business_objective'];
const missing = required.filter(f => !formData[f] && !formData[f.replace(/q\d+_/, '')]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

return $input.all();
